INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Tercero Básico', 'Ciencias Naturales', '1. Discute los resultados obtenidos a partir de la aplicación de los métodos de investigación científica, que le permitan dar solución a problemas de la vida cotidiana, utilizando diferentes recursos tecnológicos.', ARRAY['1.1. Explica la importancia del enfoque interdisciplinario en la investigación científica, así como la necesidad de hacer ciencia ciudadana en el país.', '1.2. Describe formas para realizar investigación científica y tecnológica.', '1.3. Argumenta acerca de la importancia de la innovación científica y tecnológica en Guatemala.']),
('Tercero Básico', 'Ciencias Naturales', '2. Propone soluciones prácticas a la problemática socio-ambiental local, la reducción de riesgo y la vulnerabilidad personal y local.', ARRAY['2.1. Relaciona el concepto de riesgo con la amenaza y la vulnerabilidad local.', '2.2. Discute acerca de los problemas socio-ambientales locales y sus posibles soluciones.', '2.3. Aplica el protocolo establecido en el plan de respuesta escolar para proteger su vida y la de los demás en caso de un desastre natural.']),
('Tercero Básico', 'Ciencias Naturales', '3. Argumenta acerca del cuidado personal, familiar y comunitario que procuran la salud integral.', ARRAY['3.1. Discute acerca del daño personal y social que produce el consumo de drogas, con base en información y datos estadísticos confiables.', '3.2. Explica la sexualidad humana y los posibles riesgos que implica asumirla en forma irresponsable.', '3.3. Discute acerca de la importancia de una alimentación equilibrada y los daños corporales que se producen debido a desórdenes alimenticios.']),
('Tercero Básico', 'Ciencias Naturales', '4. Resuelve problemas vinculados con los fenómenos físicos, químicos y biológicos que ocurren en su contexto.', ARRAY['4.1. Aplica los principios de la mecánica cuántica para establecer la ubicación de los electrones en un átomo.', '4.2. Establece diferencias entre átomos, moléculas y iones presentes en los compuestos.', '4.3. Utiliza números de oxidación para formar y nombrar compuestos con oxígeno, hidrógeno y sin oxígeno e hidrógeno.', '4.4. Analiza gráficas de posición, velocidad y aceleración versus tiempo y las relaciona con los modelos matemáticos relacionados con el movimiento y aceleración constante, en una dimensión.', '4.5. Resuelve problemas teóricos y experimentales de movimiento acelerado en una dimensión, de proyectiles y movimiento circular uniforme relacionados con la vida diaria.', '4.6. Aplica las leyes de Newton en la explicación de la ocurrencia de fenómenos y situaciones de la cotidianidad, del ámbito tecnológico y en la resolución de problemas de equilibrio estático en 1D.', '4.7. Explica la relación entre los conceptos de trabajo, potencia y energía mecánica en problemas de la vida cotidiana.', '4.8. Describe distintas formas de generar energía y su impacto en el medio ambiente local.']);
